package com.yourcompany.sharding.algorithm;

import com.google.common.hash.HashFunction;
import com.google.common.hash.Hashing;
import lombok.extern.slf4j.Slf4j;
import org.apache.commons.collections4.CollectionUtils;
import org.apache.shardingsphere.api.sharding.complex.ComplexKeysShardingAlgorithm;
import org.apache.shardingsphere.api.sharding.complex.ComplexKeysShardingValue;
import org.apache.shardingsphere.core.exception.ShardingException;

import java.math.BigDecimal;
import java.util.*;
import java.util.concurrent.atomic.AtomicInteger;

/**
 * 基于客户ID的一致性哈希分片算法（ShardingSphere 4.x）
 * 
 * <p>配置项（通过 init(Properties) 注入）：
 * <ul>
 *   <li>customer_id.column：客户ID字段名，默认 "customer_id"</li>
 *   <li>order_id.column：订单ID字段名，默认 "order_id"</li>
 *   <li>virtual.node.count：每物理节点虚拟节点数，默认 150</li>
 *   <li>sharding.fallback：降级策略（ROUND_ROBIN / BROADCAST / ERROR），默认 ROUND_ROBIN</li>
 * </ul>
 * 
 * <p>使用示例（YAML）：
 * <pre>
 * sharding:
 *   sharding-algorithms:
 *     customer_hash:
 *       type: CLASS_BASED
 *       props:
 *         strategy: COMPLEX
 *         algorithm-class: com.yourcompany.sharding.algorithm.CustomerIdConsistentHashShardingAlgorithm
 *         customer_id.column: customer_id
 *         virtual.node.count: 150
 *         sharding.fallback: ROUND_ROBIN
 * </pre>
 */
@Slf4j
public class CustomerIdConsistentHashShardingAlgorithm implements ComplexKeysShardingAlgorithm<BigDecimal> {

    private static final HashFunction MURMUR3 = Hashing.murmur3_32_fixed(0x1234ABCD);

    // ============== 配置缓存（init 时解析，避免重复计算） ==============
    private String customerIdColumn = "customer_id";
    private String orderIdColumn = "order_id";
    private int virtualNodeCount = 150;
    private FallbackStrategy fallbackStrategy = FallbackStrategy.ROUND_ROBIN;

    // ============== 一致性哈希环（volatile + synchronized 保证线程安全） ==============
    private volatile TreeMap<Long, String> hashRing;
    private volatile String ringVersion;

    // ============== 轮询计数器（仅用于降级 ROUND_ROBIN） ==============
    private final AtomicInteger roundRobinCounter = new AtomicInteger(0);

    /**
     * ShardingSphere 4.x 通过反射调用此方法注入配置
     * 方法签名必须为 init(Properties)，框架会自动识别
     */
    public void init(Properties props) {
        if (props == null || props.isEmpty()) {
            log.warn("Sharding properties is empty, using all defaults");
            return;
        }

        // 防御性拷贝，避免外部修改
        Properties safeProps = new Properties(props);

        // 解析并缓存配置
        this.customerIdColumn = safeProps.getProperty("customer_id.column", "customer_id");
        this.orderIdColumn = safeProps.getProperty("order_id.column", "order_id");

        try {
            this.virtualNodeCount = Integer.parseInt(
                    safeProps.getProperty("virtual.node.count", "150"));
            if (this.virtualNodeCount <= 0) {
                log.warn("virtual.node.count must be positive, using default 150");
                this.virtualNodeCount = 150;
            }
        } catch (NumberFormatException e) {
            log.error("Invalid virtual.node.count format, using default 150", e);
            this.virtualNodeCount = 150;
        }

        String fallback = safeProps.getProperty("sharding.fallback", "ROUND_ROBIN").toUpperCase();
        try {
            this.fallbackStrategy = FallbackStrategy.valueOf(fallback);
        } catch (IllegalArgumentException e) {
            log.error("Invalid fallback strategy '{}', using ROUND_ROBIN", fallback);
            this.fallbackStrategy = FallbackStrategy.ROUND_ROBIN;
        }

        log.info("ShardingAlgorithm initialized: customerIdColumn={}, orderIdColumn={}, virtualNodes={}, fallback={}",
                customerIdColumn, orderIdColumn, virtualNodeCount, fallbackStrategy);
    }

    // ============== 降级策略枚举 ==============
    public enum FallbackStrategy {
        ROUND_ROBIN,  // 轮询降级
        BROADCAST,    // 广播查询（谨慎使用）
        ERROR         // 直接抛异常（严格模式）
    }

    @Override
    public Collection<String> doSharding(Collection<String> availableTargets,
                                         ComplexKeysShardingValue<BigDecimal> shardingValue) {
        // 1. 基础校验
        if (CollectionUtils.isEmpty(availableTargets)) {
            throw new ShardingException("No available target data sources");
        }

        List<String> targetList = new ArrayList<>(availableTargets);

        // 2. 提取分片键（优先 customer_id，其次从 order_id 解析）
        BigDecimal shardingKey = extractShardingKey(shardingValue);

        // 3. 无分片键时执行降级
        if (shardingKey == null) {
            return handleFallback(targetList);
        }

        // 4. 获取/重建一致性哈希环，并路由
        TreeMap<Long, String> ring = getHashRing(targetList);
        String target = routeByConsistentHash(ring, shardingKey);
        return Collections.singletonList(target);
    }

    /**
     * 提取分片键值（取第一个有效值）
     */
    private BigDecimal extractShardingKey(ComplexKeysShardingValue<BigDecimal> shardingValue) {
        if (shardingValue == null) {
            return null;
        }
        Map<String, Collection<BigDecimal>> columnValues = 
                shardingValue.getColumnNameAndShardingValuesMap();
        if (columnValues == null) {
            return null;
        }

        // 1) 优先 customer_id
        Collection<BigDecimal> customerIds = columnValues.get(customerIdColumn);
        if (CollectionUtils.isNotEmpty(customerIds)) {
            return customerIds.iterator().next();
        }

        // 2) 降级：从 order_id 解析
        Collection<BigDecimal> orderIds = columnValues.get(orderIdColumn);
        if (CollectionUtils.isNotEmpty(orderIds)) {
            BigDecimal customerId = parseCustomerIdFromOrderId(orderIds.iterator().next());
            if (customerId != null) {
                return customerId;
            }
        }

        log.debug("No valid sharding key found: customerIdColumn={}, orderIdColumn={}", 
                customerIdColumn, orderIdColumn);
        return null;
    }

    /**
     * 从订单ID解析客户ID（业务方可重写此方法）
     * 默认返回 null，触发降级策略
     * 
     * @param orderId 订单ID
     * @return 解析出的客户ID，null 表示无法解析
     */
    protected BigDecimal parseCustomerIdFromOrderId(BigDecimal orderId) {
        // TODO: 根据业务规则实现，例如：
        // 规则1：订单号前10位是客户ID → return new BigDecimal(orderId.toPlainString().substring(0, 10));
        // 规则2：订单号包含客户ID段 → 使用正则提取
        // 规则3：查缓存/数据库映射表 → 注意避免循环依赖

        log.trace("OrderId->CustomerId mapping not implemented, orderId={}", orderId);
        return null;
    }

    /**
     * 降级处理
     */
    private Collection<String> handleFallback(List<String> availableTargets) {
        log.debug("No valid sharding key, triggering fallback strategy: {}", fallbackStrategy);

        switch (fallbackStrategy) {
            case ROUND_ROBIN:
                return Collections.singletonList(roundRobinSelect(availableTargets));

            case BROADCAST:
                log.warn("BROADCAST fallback triggered - query will scan ALL data sources! " +
                        "This may cause performance issue if data volume is large.");
                return new ArrayList<>(availableTargets);

            case ERROR:
            default:
                log.error("Sharding key required but not provided, fallback=ERROR, rejecting query");
                throw new ShardingException("Sharding key (customer_id or resolvable order_id) required, but not provided");
        }
    }

    /**
     * 获取一致性哈希环（版本感知 + 懒重建 + 双重检查锁）
     */
    private TreeMap<Long, String> getHashRing(List<String> targets) {
        String currentVersion = computeRingVersion(targets);

        // 快速路径：版本未变，直接返回缓存环（volatile 读保证可见性）
        if (currentVersion.equals(ringVersion) && hashRing != null) {
            return hashRing;
        }

        // 慢路径：需要重建，加锁保证互斥
        synchronized (this) {
            // 双重检查：防止其他线程已重建
            if (!currentVersion.equals(ringVersion)) {
                // 1. 在本地构建新环（避免部分构建状态被其他线程看到）
                TreeMap<Long, String> newRing = buildConsistentHashRing(targets);

                // 2. 原子发布：先赋值 ring，再赋值 version（volatile 写顺序保证）
                this.hashRing = newRing;
                this.ringVersion = currentVersion;

                log.info("Consistent hash ring rebuilt: nodes={}, virtualNodesPerNode={}",
                        targets.size(), virtualNodeCount);
            }
            // 返回当前环（volatile 读）
            return this.hashRing;
        }
    }

    /**
     * 计算数据源列表的版本指纹（用于检测变化）
     * 相同内容的数据源集合（顺序无关）会产生相同版本号
     */
    private String computeRingVersion(Collection<String> targets) {
        if (targets == null || targets.isEmpty()) {
            return "EMPTY";
        }
        List<String> sorted = new ArrayList<>(targets);
        Collections.sort(sorted);
        // 排序后拼接 + 哈希，确保相同内容产生相同版本号
        return String.valueOf(Objects.hash(String.join(",", sorted)));
    }

    /**
     * 构建一致性哈希环（虚拟节点）
     * 注意：此方法在锁内调用，返回的 TreeMap 是"完全构建"后才发布
     */
    private TreeMap<Long, String> buildConsistentHashRing(List<String> dataSources) {
        TreeMap<Long, String> ring = new TreeMap<>();

        if (dataSources.isEmpty()) {
            return ring;
        }

        if (dataSources.size() == 1) {
            // 单节点优化：所有哈希直接落到该节点，避免虚拟节点开销
            ring.put(0L, dataSources.get(0));
            return ring;
        }

        for (String ds : dataSources) {
            for (int i = 0; i < virtualNodeCount; i++) {
                String virtualNodeKey = ds + "#VN" + i;
                // 使用 Guava Murmur3，& 0xFFFFFFFFL 转为无符号 long
                long hash = MURMUR3.hashUnencodedChars(virtualNodeKey).asLong() & 0xFFFFFFFFL;
                ring.put(hash, ds);
            }
        }
        return ring;
    }

    /**
     * 一致性哈希路由：顺时针查找第一个 >= keyHash 的虚拟节点
     * 
     * @param ring 一致性哈希环
     * @param key 分片键
     * @return 目标数据源名称
     */
    private String routeByConsistentHash(TreeMap<Long, String> ring, BigDecimal key) {
        if (ring.isEmpty()) {
            throw new ShardingException("Consistent hash ring is empty");
        }

        long keyHash = MURMUR3.hashUnencodedChars(key.toPlainString()).asLong() & 0xFFFFFFFFL;

        // ceilingEntry: 查找第一个 >= keyHash 的 entry
        Map.Entry<Long, String> entry = ring.ceilingEntry(keyHash);
        if (entry == null) {
            // 环形结构：如果没找到，回到起点（最小 hash 的节点）
            entry = ring.firstEntry();
        }
        return entry.getValue();
    }

    /**
     * 轮询选择数据源（线程安全 + 防溢出）
     */
    private String roundRobinSelect(List<String> dataSources) {
        if (dataSources.isEmpty()) {
            throw new ShardingException("No data source for round-robin");
        }
        // & 0x7FFFFFFF 确保索引非负（避免 AtomicInteger 溢出为负数）
        int idx = roundRobinCounter.getAndIncrement() & 0x7FFFFFFF;
        return dataSources.get(Math.floorMod(idx, dataSources.size()));
    }
}
