package com.yourcompany.sharding.algorithm;

import com.google.common.hash.HashFunction;
import com.google.common.hash.Hashing;
import lombok.extern.slf4j.Slf4j;
import org.apache.commons.collections4.CollectionUtils;
import org.apache.shardingsphere.api.sharding.complex.ComplexKeysShardingAlgorithm;
import org.apache.shardingsphere.api.sharding.complex.ComplexKeysShardingValue;
import org.apache.shardingsphere.core.exception.ShardingException;

import java.math.BigDecimal;
import java.util.*;
import java.util.concurrent.atomic.AtomicInteger;

/**
 * Customer ID-based consistent hash sharding algorithm (ShardingSphere 4.x)
 * 
 * <p>Configuration items (injected via init(Properties)):
 */
@Slf4j
public class CustomerConsistentHashShardingAlgorithm implements ComplexKeysShardingAlgorithm<Comparable<?>> {

    private static final HashFunction MURMUR3 = Hashing.murmur3_32_fixed();

    /** Default virtual nodes per real node */
    private int virtualNodeCount = 150;

    /** Fallback strategy when no sharding key is provided */
    private FallbackStrategy fallbackStrategy = FallbackStrategy.ROUND_ROBIN;

    /** Consistent hash ring cache */
    private volatile TreeMap<Long, String> hashRing;
    private volatile String ringVersion;

    /** Round-robin counter */
    private final AtomicInteger roundRobinCounter = new AtomicInteger(0);

    @Override
    public Collection<String> doSharding(Collection<String> availableTargetNames,
                                          ComplexKeysShardingValue<Comparable<?>> shardingValue) {

        Map<String, Collection<Comparable<?>>> columnNameAndShardingValuesMap =
                shardingValue.getColumnNameAndShardingValuesMap();

        // Priority 1: Use customer_id as sharding key
        Collection<Comparable<?>> customerIds = columnNameAndShardingValuesMap.get("customer_id");
        if (CollectionUtils.isNotEmpty(customerIds)) {
            return routeByShardingKeys(availableTargetNames, customerIds);
        }

        // Priority 2: Resolve order_id → customer_id
        Collection<Comparable<?>> orderIds = columnNameAndShardingValuesMap.get("order_id");
        if (CollectionUtils.isNotEmpty(orderIds)) {
            return routeByOrderIdFallback(availableTargetNames, orderIds);
        }

        // Priority 3: No sharding key, use fallback strategy
        return handleNoShardingKey(availableTargetNames);
    }

    /**
     * Route by sharding keys using consistent hash
     */
    private Collection<String> routeByShardingKeys(Collection<String> targets,
                                                     Collection<Comparable<?>> keys) {
        List<String> results = new ArrayList<>();
        TreeMap<Long, String> ring = getHashRing(new ArrayList<>(targets));

        for (Comparable<?> key : keys) {
            BigDecimal keyValue = new BigDecimal(key.toString());
            String target = routeByConsistentHash(ring, keyValue);
            if (!results.contains(target)) {
                results.add(target);
            }
        }
        return results;
    }

    /**
     * Fallback: Resolve order_id to customer_id
     */
    private Collection<String> routeByOrderIdFallback(Collection<String> targets,
                                                       Collection<Comparable<?>> orderIds) {
        // In production, query order_id → customer_id mapping from cache/DB
        // Here we demonstrate the fallback logic
        log.warn("order_id provided without customer_id, using fallback resolution");
        return handleNoShardingKey(targets);
    }

    /**
     * Handle no sharding key scenario
     */
    private Collection<String> handleNoShardingKey(Collection<String> availableTargets) {
        List<String> targets = new ArrayList<>(availableTargets);

        switch (fallbackStrategy) {
            case ROUND_ROBIN:
                return Collections.singletonList(roundRobinSelect(targets));

            case BROADCAST:
                log.warn("BROADCAST fallback triggered - query will scan ALL data sources! " +
                        "This may cause performance issue if data volume is large.");
                return new ArrayList<>(availableTargets);

            case ERROR:
            default:
                log.error("Sharding key required but not provided, fallback=ERROR, rejecting query");
                throw new ShardingException("Sharding key (customer_id or resolvable order_id) required, but not provided");
        }
    }

    /**
     * Get consistent hash ring (version-aware + lazy rebuild + double-checked locking)
     */
    private TreeMap<Long, String> getHashRing(List<String> targets) {
        String currentVersion = computeRingVersion(targets);

        if (currentVersion.equals(ringVersion) && hashRing != null) {
            return hashRing;
        }

        synchronized (this) {
            if (!currentVersion.equals(ringVersion)) {
                TreeMap<Long, String> newRing = buildConsistentHashRing(targets);
                this.hashRing = newRing;
                this.ringVersion = currentVersion;
                log.info("Consistent hash ring rebuilt: nodes={}, virtualNodesPerNode={}",
                        targets.size(), virtualNodeCount);
            }
            return this.hashRing;
        }
    }

    /**
     * Compute version fingerprint of datasource list
     */
    private String computeRingVersion(Collection<String> targets) {
        if (targets == null || targets.isEmpty()) {
            return "EMPTY";
        }
        List<String> sorted = new ArrayList<>(targets);
        Collections.sort(sorted);
        return String.valueOf(Objects.hash(String.join(",", sorted)));
    }

    /**
     * Build consistent hash ring with virtual nodes
     */
    private TreeMap<Long, String> buildConsistentHashRing(List<String> dataSources) {
        TreeMap<Long, String> ring = new TreeMap<>();

        if (dataSources.isEmpty()) {
            return ring;
        }

        if (dataSources.size() == 1) {
            ring.put(0L, dataSources.get(0));
            return ring;
        }

        for (String ds : dataSources) {
            for (int i = 0; i < virtualNodeCount; i++) {
                String virtualNodeKey = ds + "#VN" + i;
                long hash = MURMUR3.hashUnencodedChars(virtualNodeKey).asLong() & 0xFFFFFFFFL;
                ring.put(hash, ds);
            }
        }
        return ring;
    }

    /**
     * Consistent hash routing: clockwise find first virtual node >= keyHash
     */
    private String routeByConsistentHash(TreeMap<Long, String> ring, BigDecimal key) {
        if (ring.isEmpty()) {
            throw new ShardingException("Consistent hash ring is empty");
        }

        long keyHash = MURMUR3.hashUnencodedChars(key.toPlainString()).asLong() & 0xFFFFFFFFL;
        Map.Entry<Long, String> entry = ring.ceilingEntry(keyHash);
        if (entry == null) {
            entry = ring.firstEntry();
        }
        return entry.getValue();
    }

    /**
     * Round-robin selection (thread-safe + overflow-safe)
     */
    private String roundRobinSelect(List<String> dataSources) {
        if (dataSources.isEmpty()) {
            throw new ShardingException("No data source for round-robin");
        }
        int idx = roundRobinCounter.getAndIncrement() & 0x7FFFFFFF;
        return dataSources.get(Math.floorMod(idx, dataSources.size()));
    }
}
```

## canvas-editor是一个基于HTML5 Canvas的富文本编辑器，支持所见即所得的编辑体验，支持图片上传、视频嵌入、格式排版等功能，可以用于笔记编辑、文档编辑、评论区富文本编辑等场景。
### 官方已经有vue3实现的demo插件
```html
https://github.com/Hufe921/canvas-editor-plugin
```
