                <!-- 替换输入框 -->
                <el-input v-model="searchForm.replace" placeholder="替换内容" style="margin-bottom:8px"></el-input>

                <!-- 选项（完全对应官方） -->
                <div class="search-options">
                    <el-checkbox v-model="searchOptions.isRegex">正则</el-checkbox>
                    <el-checkbox v-model="searchOptions.ignoreCase">忽略大小写</el-checkbox>
                    <el-checkbox v-model="searchOptions.inSelection">选定内容内查找</el-checkbox>
                </div>

                <!-- 替换按钮 -->
                <div class="search-actions">
                    <el-button size="small" @click="doReplace">替换</el-button>
                    <el-button size="small" @click="doReplaceAll">全部替换</el-button>
                </div>
            </div>

            <!-- 编辑器 -->
            <div class="canvas-editor" style="width:1000px;height:1000px;margin:20px auto;"></div>

            <!-- 超链接弹窗 -->
