    </div>
</template>

<script>
import Editor from '@hufe921/canvas-editor'

export default {
    data() {
        return {
            instance: null,
            fontName: '微软雅黑',
            sizeName: '小四',
            fontColor: '#000',
            bgColor: '#ff0',
            showSearch: false,
            searchTop: 0,
            searchLeft: 0,
            searchForm: { key: '', replace: '' },
            searchOptions: { isIgnoreCase: true },
            fontList: [
                { label: '微软雅黑', value: 'Microsoft YaHei' }, { label: '宋体', value: 'SimSun' },
                { label: '黑体', value: 'SimHei' }, { label: '楷体', value: 'KaiTi' },
                { label: '仿宋', value: 'FangSong' }, { label: '华文宋体', value: '华文宋体' },
                { label: '华文黑体', value: '华文黑体' }, { label: '华文仿宋', value: '华文仿宋' },
                { label: '华文楷体', value: '华文楷体' }, { label: '华文琥珀', value: '华文琥珀' },
                { label: '华文隶书', value: '华文隶书' }, { label: '华文新魏', value: '华文新魏' },
                { label: '华文行楷', value: '华文行楷' }, { label: '华文中宋', value: '华文中宋' },
                { label: '华文彩云', value: '华文彩云' }, { label: 'Arial', value: 'Arial' },
                { label: 'Segoe UI', value: 'Segoe UI' }, { label: 'Ink Free', value: 'Ink Free' }, { label: 'Fantasy', value: 'Fantasy' }
            ],
            sizeList: [
                { label: '初号', value: 56 }, { label: '小初', value: 48 },
                { label: '一号', value: 34 }, { label: '小一', value: 32 },
                { label: '二号', value: 29 }, { label: '小二', value: 24 },
                { label: '三号', value: 21 }, { label: '小三', value: 20 },
                { label: '四号', value: 18 }, { label: '小四', value: 16 },
                { label: '五号', value: 14 }, { label: '小五', value: 12 },
                { label: '六号', value: 10 }, { label: '小六', value: 8 },
                { label: '七号', value: 7 }, { label: '八号', value: 6 }
            ],
            underlineList: [
                { label: '实线', value: 'solid' }, { label: '双线', value: 'double' },
                { label: '波浪线', value: 'wavy' }, { label: '点线', value: 'dotted' }, { label: '虚线', value: 'dashed' },
            ],
            listList: [
                { label: '有序', value: 'ol,ordered' }, { label: '实心圆', value: 'ul,disc' },
                { label: '复选', value: 'ul,checkbox' }, { label: '空心圆', value: 'ul,circle' }, { label: '空心块', value: 'ul,square' },
            ],
            alignList: [
                { label: '左对齐', value: 'left' }, { label: '居中对齐', value: 'center' },
                { label: '右对齐', value: 'right' }, { label: '两端对齐', value: 'justify' },
            ],
            linkDialogVisible: false,
            selectedLinkText: '',
            linkUrl: '',
            searchInfo: { index: 0, count: 0 },
            isBold: false,
            isItalic: false,
            isUnderline: false,
            isStrikeout: false,
            isSuperscript: false,
            isSubscript: false,
            currentAlign: 'left',
            currentListType: null,
            currentListStyle: null,
        }
    },
    mounted() {
        this.init()
    },
    methods: {
        init() {
            this.instance = new Editor(document.querySelector('.canvas-editor'), {
                main: [{ value: '请输入内容\n' }],
                contextmenu: true
            })
            this.instance.eventBus.on('rangeStyleChange', (payload) => {
                this.syncToolbar(payload)
            })
        },
        // 同步工具栏状态
        // 官方原版：同步工具栏样式
        syncToolbar(payload) {
            if (!payload || payload.type === null) return

            // ======================
            // 1. 同步字体（正确回显）
            // ======================
            if (payload.font) {
                const fontItem = this.fontList.find(item => item.value === payload.font)
                this.fontName = fontItem ? fontItem.label : payload.font
            }

            // ======================
            // 2. 同步字号（区间匹配最小）
            // ======================
            if (payload.size) {
                const validSizes = this.sizeList
                    .filter(item => item.value <= payload.size)
                    .sort((a, b) => b.value - a.value)
                this.sizeName = validSizes[0]?.label || '小四'
            }

            // ======================
            // 3. 同步颜色（修复不生效）
            // ======================
            if (payload.color !== undefined) {
                this.fontColor = payload.color || '#000000'
            }
            if (payload.highlight !== undefined) {
                this.bgColor = payload.highlight || '#ffffff'
            }

            // ======================
            // 4. 同步文字样式
            // ======================
            this.isBold = !!payload.bold
            this.isItalic = !!payload.italic
            this.isUnderline = payload.underline === true
            this.isStrikeout = !!payload.strikeout
            this.isSuperscript = payload.type === 'superscript'
            this.isSubscript = payload.type === 'subscript'

            // ======================
            // 5. 同步段落对齐
            // ======================
            if (payload.rowFlex !== undefined) {
                this.currentAlign = payload.rowFlex
            }

            // ======================
            // 6. 同步列表
            // ======================
            if (payload.listType !== undefined) {
                this.currentListType = payload.listType
                this.currentListStyle = payload.listStyle || null
            } else {
                this.currentListType = null
                this.currentListStyle = null
            }
        },
        executePainter(isDblclick) { this.instance.command.executePainter(isDblclick) },
        clearFormat() { this.instance.command.executeFormat() },
        undo() { this.instance.command.executeUndo() },
        redo() { this.instance.command.executeRedo() },
        setFont(val) { this.fontName = val; this.instance.command.executeFont(val) },
        setSize(val) {
            const map = { 56: '初号', 48: '小初', 34: '一号', 16: '小四', 14: '五号' }
            this.sizeName = map[val] || val
            this.instance.command.executeSize(val)
        },
        sizeAdd() { this.instance.command.executeSizeAdd() },
        sizeSub() { this.instance.command.executeSizeMinus() },
        setBold() { this.instance.command.executeBold() },
        setItalic() { this.instance.command.executeItalic() },
        setUnderline(val) { this.instance.command.executeUnderline({ style: val }) },
        setStrikeout() { this.instance.command.executeStrikeout() },
        setSuperscript() { this.instance.command.executeSuperscript() },
        setSubscript() { this.instance.command.executeSubscript() },
        setColor(val) { this.instance.command.executeColor(val) },
        setHighlight(val) { this.instance.command.executeHighlight(val) },
        setAlign(val) { this.instance.command.executeRowFlex(val) },
        setList(val) {
            const [type, style] = val.split(',')
            this.instance.command.executeList(type, style)
        },
        insertImage(e) {
            const file = e.target.files[0]
            if (!file) return
            const reader = new FileReader()
            reader.onload = (ev) => {
                const img = new Image()
                img.src = ev.target.result
                img.onload = () => {
                    this.instance.command.executeImage({
                        value: ev.target.result,
                        width: img.width,
                        height: img.height
                    })
                }
            }
            reader.readAsDataURL(file)
            e.target.value = ''
        },
        insertLink() {
            this.selectedLinkText = this.instance.command.getRangeText() || ''
            this.linkUrl = ''
            this.linkDialogVisible = true
        },
        handleLinkConfirm(data) {
            const { text, url } = data
            this.linkDialogVisible = false
            if (!url) return
            const size = this.sizeList.find(s => s.label === this.sizeName)?.value || 16
            this.instance.command.executeHyperlink({
                type: 'hyperlink',
                url: url,
                valueList: text.split('').map(t => ({ value: t, size }))
            })
        },
        insertSplitLine() { this.instance.command.executeSeparator([1]) },
        addWatermark() { this.instance.command.executeAddWatermark({ data: '内部资料' }) },
        insertPageBreak() { this.instance.command.executePageBreak() },
        openSearch() {
            const rect = this.$refs.searchBtn.$el.getBoundingClientRect()
            this.searchTop = rect.bottom + 10
            this.searchLeft = rect.left - 200
            this.showSearch = true
        },
        closeSearch() {
            this.showSearch = false; this.instance.command.executeSearchExit(); this.setSearchResult()
        },
        doSearch() { this.instance.command.executeSearch(this.searchForm.key, this.searchOptions); this.setSearchResult() },
        doSearchPrev() { this.instance.command.executeSearchNavigatePre(); this.setSearchResult() },
        doSearchNext() { this.instance.command.executeSearchNavigateNext(); this.setSearchResult() },
        doReplace() { this.instance.command.executeReplace(this.searchForm.replace, { index: this.searchInfo.index == 0 ? 0 : this.searchInfo.index - 1 }); this.setSearchResult() },
        doReplaceAll() { this.instance.command.executeReplace(this.searchForm.replace); this.setSearchResult() },
        setSearchResult() {
            const result = this.instance.command.getSearchNavigateInfo()
            if (result) {
                this.searchInfo = result
            } else {
                this.searchInfo = { index: 0, count: 0 }
            }
        },
        doPrint() { this.instance.command.executePrint() },
        getAllData() {
            console.log('HTML', this.instance.command.getHTML())
            console.log('TEXT', this.instance.command.getText())
            this.$message.success('获取成功')
        }
    }
}
</script>

