### TCP Server (Swift)

```swift
import Foundation
import Network

class TCPServer {
    private var listener: NWListener?
    private var clients: [String: TCPClientHandler] = [:]
    private let queue = DispatchQueue(label: "tcp-server")

    var onStarted: (() -> Void)?
    var onClientConnected: ((String) -> Void)?
    var onClientDisconnected: ((String) -> Void)?
    var onMessageReceived: ((String, String) -> Void)?

    func start(port: UInt16) {
        do {
            let parameters = NWParameters.tcp
            listener = try NWListener(using: parameters, on: NWEndpoint.Port(rawValue: port)!)

            listener?.stateUpdateHandler = { state in
                switch state {
                case .ready:
                    DispatchQueue.main.async { self.onStarted?() }
                case .failed(let error):
                    print("Server failed: \(error)")
                default:
                    break
                }
            }

            listener?.newConnectionHandler = { [weak self] connection in
                self?.handleNewConnection(connection)
            }

            listener?.start(queue: queue)
        } catch {
            print("Failed to start server: \(error)")
        }
    }

    func stop() {
        listener?.cancel()
        clients.removeAll()
    }

    func sendToClient(clientId: String, msg: String) {
        clients[clientId]?.send(message: msg)
    }

    func broadcast(msg: String) {
        clients.values.forEach { $0.send(message: msg) }
    }

    func getClientList() -> [String] {
        return Array(clients.keys)
    }

    private func handleNewConnection(_ connection: NWConnection) {
        let host = connection.endpoint.host.debugDescription.replacingOccurrences(of: "\"", with: "")
        let port = connection.endpoint.port?.rawValue ?? 0
        let clientId = "\(host):\(port)"

        let handler = TCPClientHandler(connection: connection, clientId: clientId, server: self)
        clients[clientId] = handler

        connection.start(queue: queue)
        handler.start()

        DispatchQueue.main.async {
            self.onClientConnected?(clientId)
        }
    }

    func clientDisconnected(clientId: String) {
        clients.removeValue(forKey: clientId)
        DispatchQueue.main.async {
            self.onClientDisconnected?(clientId)
        }
    }

    func messageReceived(clientId: String, message: String) {
        DispatchQueue.main.async {
            self.onMessageReceived?(clientId, message)
        }
    }
}

class TCPClientHandler {
    private let connection: NWConnection
    private let clientId: String
    private weak var server: TCPServer?
    private var messageBuffer: Data = Data()

    init(connection: NWConnection, clientId: String, server: TCPServer) {
        self.connection = connection
        self.clientId = clientId
        self.server = server
    }

    func start() {
        receiveMessage()
    }

    func close() {
        connection.cancel()
    }

    func send(message: String) {
        let messageWithNewline = message.hasSuffix("\n") ? message : message + "\n"
        guard let data = messageWithNewline.data(using: .utf8) else { return }

        connection.send(content: data, completion: .contentProcessed { error in
            if let error = error {
                print("Send error: \(error.localizedDescription)")
            }
        })
    }

    private func receiveMessage() {
        connection.receive(minimumIncompleteLength: 1, maximumLength: 65536) { [weak self] data, context, isComplete, error in
            guard let self = self else { return }

            if let data = data, !data.isEmpty {
                self.messageBuffer.append(data)

                while let newlineRange = self.messageBuffer.range(of: Data([0x0A])) {
                    let messageData = self.messageBuffer.subdata(in: self.messageBuffer.startIndex..<newlineRange.lowerBound)
                    self.messageBuffer.removeSubrange(self.messageBuffer.startIndex..<newlineRange.upperBound)

                    if let message = String(data: messageData, encoding: .utf8) {
                        let trimmedMessage = message.trimmingCharacters(in: .whitespacesAndNewlines)
                        if !trimmedMessage.isEmpty {
                            self.server?.messageReceived(clientId: self.clientId, message: trimmedMessage)
                        }
                    }
                }
            }

            if isComplete {
                self.server?.clientDisconnected(clientId: self.clientId)
                return
            }

            if let error = error {
                print("Receive error: \(error.localizedDescription)")
                self.server?.clientDisconnected(clientId: self.clientId)
                return
            }

            self.receiveMessage()
        }
    }
}
