#### 同目录 TCPClient.kt
```javascript
package uts.sdk.modules.redTcp

import java.io.BufferedReader
import java.io.BufferedWriter
import java.io.InputStreamReader
import java.io.OutputStreamWriter
import java.net.Socket
import java.util.concurrent.TimeUnit



/**
 * android平台tcp客户端实现类
 */
class TCPClient(private val clientId: String) {

    // 连接状态
    private var connectionState: String = "disconnected"

    // socket相关
    private var socket: Socket? = null
    private var reader: BufferedReader? = null
    private var writer: BufferedWriter? = null

    // 回调函数
    private var connectedCallback: ConnectedCallbackType? = null
    private var disconnectedCallback: DisconnectedCallbackType? = null
    private var messageCallback: MessageCallbackType? = null
    private var errorCallback: ErrorCallbackType? = null

    // 连接配置
    private var connectionOptions: ConnectionOptionsType? = null

    // 心跳相关
    private var heartbeatEnabled: Boolean = false
    private var heartbeatInterval: Long = 30000L // 默认30秒
    private var heartbeatMessage: String = "HEARTBEAT"
    private var heartbeatRunnable: Runnable? = null
    private var isHeartbeatActive: Boolean = false


    /**
     * 连接到服务器
     */
    fun connect(options: ConnectionOptionsType) {
        if (connectionState != "disconnected") {
            notifyError(TCPResultType(code = 1, error = "Client is not disconnected"))
            return
        }

        connectionOptions = options
        connectionState = "connecting"

        // 设置心跳配置
        connectionOptions?.enableHeartbeat?.let { enable ->
            if (enable) {
                heartbeatEnabled = true
                connectionOptions?.heartbeatInterval?.let { interval ->
                    heartbeatInterval = interval.toLong()
                }
                connectionOptions?.heartbeatMessage?.let { message ->
                    heartbeatMessage = message
                }
            }
        }

        TCPClientManager.executeOnThreadPool(Runnable {
            try {
                val timeout = connectionOptions?.timeout?.toInt()  ?: 5000
                socket = Socket()
                socket?.connect(
                    java.net.InetSocketAddress(connectionOptions?.serverHost, connectionOptions?.serverPort?.toInt() ?: 0),
                    timeout
                )

                if (socket?.isConnected == true) {
                    reader = BufferedReader(InputStreamReader(socket?.getInputStream()))
                    writer = BufferedWriter(OutputStreamWriter(socket?.getOutputStream()))

                    connectionState = "connected"

                    // 启动消息接收线程
                    startMessageReceiver()

                    // 启动心跳
                    startHeartbeat()

                    // 通知连接成功
                    notifyConnected(TCPResultType(code = 0, data = "Connected successfully"))
                } else {
                    connectionState = "disconnected"
                    notifyError(TCPResultType(code = 2, error = "Failed to connect to server"))
                }
            } catch (e: Exception) {
                connectionState = "disconnected"
                notifyError(TCPResultType(code = 3, error = e.message ?: "Unknown connection error"))
            }
        })
    }

    /**
     * 断开连接
     */
    fun disconnect() {
        if (connectionState == "disconnected" || connectionState == "disconnecting") {
            return
        }

        connectionState = "disconnecting"

        // 停止心跳
        stopHeartbeat()

        TCPClientManager.executeOnThreadPool(Runnable {
            try {
                // 安全地关闭资源，按正确顺序
                writer?.apply {
                    flush()
                    close()
                }
                reader?.close()
                socket?.close()

                connectionState = "disconnected"
                notifyDisconnected(TCPResultType(code = 0, data = "Disconnected successfully"))
            } catch (e: Exception) {
                connectionState = "disconnected"
                notifyError(TCPResultType(code = 4, error = e.message ?: "Unknown disconnection error"))
            } finally {
                // 确保资源被清理
                writer = null
                reader = null
                socket = null
            }
        })
    }

    /**
     * 发送消息
     */
    fun sendMessage(message: String) {
        if (connectionState != "connected") {
            notifyError(TCPResultType(code = 5, error = "Client is not connected"))
            return
        }

        TCPClientManager.executeOnThreadPool(Runnable {
            try {
                // 🔥 添加换行符，确保服务端能正确识别消息边界
                val messageWithNewline = if (message.endsWith("\n")) message else "$message\n"
                writer?.write(messageWithNewline)
                writer?.flush()
            } catch (e: Exception) {
                notifyError(TCPResultType(code = 6, error = e.message ?: "Failed to send message"))
            }
        })
    }

    /**
     * 获取连接状态
     */
    fun getConnectionState(): String {
        return connectionState
    }

    /**
     * 销毁客户端实例
     */
    fun destroy() {
        disconnect()
    }

    /**
     * 注册连接成功回调
     */
    fun onConnected(callback: ConnectedCallbackType) {
        connectedCallback = callback
    }

    /**
     * 注册断开连接回调
     */
    fun onDisconnected(callback: DisconnectedCallbackType) {
        disconnectedCallback = callback
    }

    /**
     * 注册消息接收回调
     */
    fun onMessage(callback: MessageCallbackType) {
        messageCallback = callback
    }

    /**
     * 注册错误回调
     */
    fun onError(callback: ErrorCallbackType) {
        errorCallback = callback
    }

    /**
     * 启用心跳
     */
    fun enableHeartbeat(interval: Int = 30000, message: String = "HEARTBEAT") {
        heartbeatEnabled = true
        heartbeatInterval = interval.toLong()
        heartbeatMessage = message

        // 如果已连接，立即启动心跳
        if (connectionState == "connected") {
            startHeartbeat()
        }
    }

    /**
     * 禁用心跳
     */
    fun disableHeartbeat() {
        heartbeatEnabled = false
        stopHeartbeat()
    }

    /**
     * 启动心跳
     */
    private fun startHeartbeat() {
        if (!heartbeatEnabled || connectionState != "connected") {
            return
        }

        // 停止之前的心跳
        stopHeartbeat()

        isHeartbeatActive = true

        heartbeatRunnable = object : Runnable {
            override fun run() {
                // 检查心跳是否仍然活跃
                if (isHeartbeatActive && heartbeatEnabled && connectionState == "connected") {
                    sendHeartbeat()
                    // 继续调度下一次心跳
                    TCPClientManager.scheduleOnThreadPool(this, heartbeatInterval, TimeUnit.MILLISECONDS)
                }
            }
        }

        // 启动心跳
        TCPClientManager.scheduleOnThreadPool(heartbeatRunnable!!, heartbeatInterval, TimeUnit.MILLISECONDS)
    }

    /**
     * 停止心跳
     */
    private fun stopHeartbeat() {
        isHeartbeatActive = false
        heartbeatRunnable = null
    }

    /**
     * 发送心跳消息
     */
    private fun sendHeartbeat() {
        if (!isHeartbeatActive || !heartbeatEnabled || connectionState != "connected") {
            return
        }

        TCPClientManager.executeOnThreadPool(Runnable {
            try {
                writer?.write(heartbeatMessage + "\n")  // 添加换行符确保消息完整
                writer?.flush()
            } catch (e: Exception) {
                // 心跳发送失败不需要特殊处理，让正常的错误处理机制处理
            }
        })
    }

    /**
     * 启动消息接收线程
     */
    private fun startMessageReceiver() {
        TCPClientManager.executeOnThreadPool(Runnable {
            try {
                while (connectionState == "connected" && socket?.isConnected == true) {
                    val message = reader?.readLine()
                    if (message != null) {
                        // 验证消息内容
                        if (message.isNotBlank()) {
                            notifyMessage(message)
                        }
                    } else {
                        // 服务器关闭了连接
                        break
                    }
                }

                // 如果循环结束，说明连接已断开
                if (connectionState == "connected") {
                    connectionState = "disconnected"
                    notifyDisconnected(TCPResultType(code = 0, data = "Server closed the connection"))
                }
            } catch (e: Exception) {
                if (connectionState == "connected") {
                    connectionState = "disconnected"
                    notifyError(TCPResultType(code = 8, error = e.message ?: "Message receiver error"))
                }
            }
        })
    }





    /**
     * 通知连接成功
     */
    private fun notifyConnected(result: TCPResultType) {
        TCPClientManager.executeOnMainThread(Runnable {
            connectedCallback?.invoke(clientId, result)
        })
    }

    /**
     * 通知断开连接
     */
    private fun notifyDisconnected(result: TCPResultType) {
        TCPClientManager.executeOnMainThread(Runnable {
            disconnectedCallback?.invoke(clientId, result)
        })
    }

    /**
     * 通知接收到消息
     */
    private fun notifyMessage(message: String) {
        TCPClientManager.executeOnMainThread(Runnable {
            messageCallback?.invoke(clientId, message)
        })
    }

    /**
     * 通知错误
     */
    private fun notifyError(result: TCPResultType) {
        TCPClientManager.executeOnMainThread(Runnable {
            errorCallback?.invoke(clientId, result)
        })
    }
}
