/**
 * TCP客户端管理器
 * 负责统一管理所有TCP客户端实例和线程资源
 * 使用object关键字实现单例模式
 */
object TCPClientManager {

    // 存储所有活跃的客户端实例
    private val activeClients = mutableMapOf<String, TCPClient>()

    // 全局线程池，用于所有TCP客户端的异步操作
    private val executorService = Executors.newCachedThreadPool()

    // 全局调度器，用于心跳等定时任务
    private val scheduledExecutor: ScheduledExecutorService = Executors.newSingleThreadScheduledExecutor()

    // 主线程handler，用于回调
    private val mainHandler = Handler(Looper.getMainLooper())

    /**
     * 创建TCP客户端实例
     * @return 客户端ID
     */
    fun createTCPClient(): String {
        val clientId = "client_${System.currentTimeMillis()}_${(Math.random() * 1000000).toInt().toString(36)}"
        val client = TCPClient(clientId)
        activeClients[clientId] = client
        return clientId
    }

    /**
     * 通过客户端ID获取TCP客户端实例
     * @param clientId 客户端ID
     * @return TCP客户端实例，如果不存在则返回null
     */
    fun getTCPClient(clientId: String): TCPClient? {
        return activeClients[clientId]
    }

    /**
     * 通过客户端ID连接到服务器
     * @param clientId 客户端ID
     * @param options 连接选项
     */
    fun connectClient(clientId: String, options: ConnectionOptionsType) {
        val client = activeClients[clientId]
        if (client != null) {
            client.connect(options)
        }
    }

    /**
     * 通过客户端ID断开连接
     * @param clientId 客户端ID
     */
    fun disconnectClient(clientId: String) {
        val client = activeClients[clientId]
        client?.disconnect()
    }

    /**
     * 通过客户端ID销毁客户端
     * @param clientId 客户端ID
     */
    fun destroyClient(clientId: String) {
        val client = activeClients[clientId]
        if (client != null) {
            client.destroy()
            activeClients.remove(clientId)
        }
    }

    /**
     * 通过客户端ID发送消息
     * @param clientId 客户端ID
     * @param message 消息内容
     */
    fun sendMessage(clientId: String, message: String) {
        val client = activeClients[clientId]
        if (client != null && message.isNotBlank()) {
            client.sendMessage(message)
        }
    }

    /**
     * 通过客户端ID注册连接成功回调
     * @param clientId 客户端ID
     * @param callback 连接成功回调函数
     */
    fun onConnected(clientId: String, callback: ConnectedCallbackType) {
        val client = activeClients[clientId]
        client?.onConnected(callback)
    }

    /**
     * 通过客户端ID注册断开连接回调
     * @param clientId 客户端ID
     * @param callback 断开连接回调函数
     */
    fun onDisconnected(clientId: String, callback: DisconnectedCallbackType) {
        val client = activeClients[clientId]
        client?.onDisconnected(callback)
    }

    /**
     * 通过客户端ID注册消息接收回调
     * @param clientId 客户端ID
     * @param callback 消息接收回调函数
     */
    fun onMessage(clientId: String, callback: MessageCallbackType) {
        val client = activeClients[clientId]
        client?.onMessage(callback)
    }

    /**
     * 通过客户端ID注册错误回调
     * @param clientId 客户端ID
     * @param callback 错误回调函数
     */
    fun onError(clientId: String, callback: ErrorCallbackType) {
        val client = activeClients[clientId]
        client?.onError(callback)
    }

    /**
     * 获取所有活跃的客户端ID
     * @return 客户端ID列表
     */
    fun getActiveClients(): List<String> {
        return activeClients.keys.toList()
    }

    /**
     * 获取客户端连接状态
     * @param clientId 客户端ID
     * @return 连接状态，如果客户端不存在返回"not_found"
     */
    fun getClientState(clientId: String): String {
        val client = activeClients[clientId]
        return client?.getConnectionState() ?: "not_found"
    }

    /**
     * 检查客户端是否存在
     * @param clientId 客户端ID
     * @return 是否存在
     */
    fun clientExists(clientId: String): Boolean {
        return activeClients.containsKey(clientId)
    }

    /**
     * 启用客户端心跳
     * @param clientId 客户端ID
     * @param interval 心跳间隔，单位毫秒
     * @param message 心跳消息内容
     */
    fun enableHeartbeat(clientId: String, interval: Int = 30000, message: String = "HEARTBEAT") {
        val client = activeClients[clientId]
        client?.enableHeartbeat(interval, message)
    }

    /**
     * 禁用客户端心跳
     * @param clientId 客户端ID
     */
    fun disableHeartbeat(clientId: String) {
        val client = activeClients[clientId]
        client?.disableHeartbeat()
    }

    /**
     * 销毁所有客户端实例
     */
    fun destroyAllClients() {
        activeClients.values.forEach { client ->
            client.destroy()
        }
        activeClients.clear()
    }

    /**
     * 在全局线程池中执行任务
     * @param task 要执行的任务
     */
    fun executeOnThreadPool(task: Runnable) {
        executorService.execute(task)
    }

    /**
     * 在全局调度器中执行定时任务
     * @param task 要执行的任务
     * @param delay 延迟时间（毫秒）
     * @param unit 时间单位
     */
    fun scheduleOnThreadPool(task: Runnable, delay: Long, unit: TimeUnit) {
        scheduledExecutor.schedule(task, delay, unit)
    }



    /**
     * 在主线程中执行任务
     * @param task 要执行的任务
     */
    fun executeOnMainThread(task: Runnable) {
        mainHandler.post(task)
    }

    /**
     * 销毁管理器，释放所有资源
     */
    fun destroy() {
        destroyAllClients()
        executorService.shutdown()
        scheduledExecutor.shutdown()
    }
}
