package uts.sdk.modules.redTcp

import java.net.ServerSocket
import java.net.Socket
import java.io.BufferedReader
import java.io.BufferedWriter
import java.io.InputStreamReader
import java.io.OutputStreamWriter
import java.util.concurrent.Executors
import java.util.concurrent.ConcurrentHashMap
import android.util.Log
import android.os.Handler
import android.os.Looper


class TCPServer {
    private var serverSocket: ServerSocket? = null
    private var isRunning = false
    private val clientPool = Executors.newCachedThreadPool()
    private val clients = ConcurrentHashMap<String, ClientHandler>()

    // 🔥 最标准、最稳定、官方插件都这么写
    var onStarted: (() -> Unit)? = null
    var onClientConnected: ((String) -> Unit)? = null
    var onClientDisconnected: ((String) -> Unit)? = null
    var onMessageReceived: ((String, String) -> Unit)? = null
    var onError: ((String) -> Unit)? = null

    fun start(port: Int) {
        if (isRunning) return
        isRunning = true

        Thread {
            try {
                serverSocket = ServerSocket(port)
               Handler(Looper.getMainLooper()).post {
                   onStarted?.invoke()
               }

                while (isRunning) {
                    val clientSocket = serverSocket?.accept()
                    clientSocket?.let {
                        val handler = ClientHandler(it, this)
                        val clientId = (it.inetAddress.hostAddress ?: "unknown") + ":" + it.port
                        clients[clientId] = handler
                        clientPool.execute(handler)
                        Handler(Looper.getMainLooper()).post {
                            onClientConnected?.invoke(clientId)
                        }
                    }
                }
            } catch (e: Exception) {
                onError?.invoke("Server error: ${e.message}")
                isRunning = false
            }
        }.start()
    }

    fun stop() {
        isRunning = false
        serverSocket?.close()
        clients.values.forEach { it.close() }
        clients.clear()
    }

    fun sendToClient(clientId: String, msg: String) {
        clients[clientId]?.send(msg)
    }

    fun broadcast(msg: String) {
        clients.values.forEach { it.send(msg) }
    }

    fun getClientList(): List<String> {
        return ArrayList(clients.keys)
    }

    inner class ClientHandler(
        private val socket: Socket,
        private val server: TCPServer
    ) : Runnable {
        private var writer: BufferedWriter? = null
        private var reader: BufferedReader? = null
        private val clientId = (socket.inetAddress.hostAddress ?: "unknown") + ":" + socket.port

        fun close() {
            try {
                reader?.close()
                writer?.close()
                socket.close()
            } catch (e: Exception) {}
        }

        fun send(msg: String) {
            try {
                writer?.write(msg + "\n")
                writer?.flush()
            } catch (e: Exception) {}
        }

        override fun run() {
            try {
                reader = BufferedReader(InputStreamReader(socket.getInputStream()))
                writer = BufferedWriter(OutputStreamWriter(socket.getOutputStream()))

                val buffer = CharArray(1024)
                var len: Int
                while (socket.isConnected && server.isRunning) {
                    len = reader?.read(buffer) ?: -1
                    if (len == -1) break
                    val msg = String(buffer, 0, len).trim()
                    if (msg.isNotEmpty()) {
                        Handler(Looper.getMainLooper()).post {
                            server.onMessageReceived?.invoke(clientId, msg)
                        }
                    }
                }
            } catch (e: Exception) {
            } finally {
                close()
                clients.remove(clientId)
                Handler(Looper.getMainLooper()).post {
                    onClientDisconnected?.invoke(clientId)
                }
            }
        }
    }
}
