package uts.sdk.modules.redTcp

class TCPServerManager {
    companion object {
        val instance = TCPServerManager()
    }

    private var server: TCPServer? = null

    // 🔥 保存回调引用，以便在创建新实例时重新绑定
    private var savedOnStarted: (() -> Unit)? = null
    private var savedOnClientConnected: ((String) -> Unit)? = null
    private var savedOnClientDisconnected: ((String) -> Unit)? = null
    private var savedOnMessageReceived: ((String, String) -> Unit)? = null
    private var savedOnError: ((String) -> Unit)? = null

    fun startServer(port: Int) {
        // 🔥 如果已经存在服务端实例，先停止
        if (server != null) {
            server?.stop()
        }

        // 🔥 创建新实例
        server = TCPServer()

        // 🔥 重新绑定之前保存的回调
        server?.onStarted = savedOnStarted
        server?.onClientConnected = savedOnClientConnected
        server?.onClientDisconnected = savedOnClientDisconnected
        server?.onMessageReceived = savedOnMessageReceived
        server?.onError = savedOnError

        server?.start(port)
    }

    fun stopServer() {
        server?.stop()
        server = null
    }

    fun sendToClient(clientId: String, msg: String) {
        server?.sendToClient(clientId, msg)
    }

    fun broadcast(msg: String) {
        server?.broadcast(msg)
    }

    fun getClients(): List<String> {
        return server?.getClientList() ?: emptyList()
    }

    // 🔥 保存回调引用，不自动创建实例
    fun onStarted(callback: () -> Unit) {
        savedOnStarted = callback
        server?.onStarted = callback
    }

    fun onClientConnected(callback: (String) -> Unit) {
        savedOnClientConnected = callback
        server?.onClientConnected = callback
    }

    fun onClientDisconnected(callback: (String) -> Unit) {
        savedOnClientDisconnected = callback
        server?.onClientDisconnected = callback
    }

    fun onMessageReceived(callback: (String, String) -> Unit) {
        savedOnMessageReceived = callback
        server?.onMessageReceived = callback
    }

    fun onError(callback: (String) -> Unit) {
        savedOnError = callback
        server?.onError = callback
    }
}

