import DCloudUTSFoundation
import Foundation
import Network

/**
 * 从interface.uts导入的类型
 */

/**
 * ios平台tcp客户端实现类
 */
class TCPClient {

    // 客户端ID
    private let clientId: String

    // 连接状态
    private var connectionState: String = "disconnected"

    // 网络连接相关
    private var connection: NWConnection?
    private var queue: DispatchQueue

    // 回调函数
    private var connectedCallback: ConnectedCallbackType?
    private var disconnectedCallback: DisconnectedCallbackType?
    private var messageCallback: MessageCallbackType?
    private var errorCallback: ErrorCallbackType?

    // 连接配置
    private var connectionOptions: ConnectionOptionsType?

    // 心跳相关
    private var heartbeatTimer: Timer?
    private var heartbeatEnabled: Bool = false
    private var heartbeatInterval: TimeInterval = 30.0
    private var heartbeatMessage: String = "HEARTBEAT"

    // 线程管理器引用
    private let threadManager = TCPClientManager.shared

    init(clientId: String) {
        self.clientId = clientId
        self.queue = DispatchQueue(label: "com.ohyes.tcp.client.\(clientId)")
    }

    /**
     * 连接到服务器
     */
    func connect(options: ConnectionOptionsType) {
        guard connectionState == "disconnected" else {
            notifyError(TCPResultType(UTSJSONObject([
                "code": 1,
                "error": "Client is not disconnected"
            ])))
            return
        }

        connectionOptions = options
        connectionState = "connecting"

        // 设置心跳配置
        if options.enableHeartbeat {
            heartbeatEnabled = true
            if let interval = options.heartbeatInterval {
                heartbeatInterval = TimeInterval(interval.doubleValue) / 1000.0 // 转换为秒
            }
            if let message = options.heartbeatMessage {
                heartbeatMessage = message
            }
        }

        guard let host = connectionOptions?.serverHost,
              let port = connectionOptions?.serverPort else {
            connectionState = "disconnected"
            notifyError(TCPResultType(UTSJSONObject([
                "code": 2,
                "error": "Invalid host or port"
            ])))
            return
        }

        let nwHost = NWEndpoint.Host(host)
        let nwPort = NWEndpoint.Port(rawValue: UInt16(truncating: port))!

        let tcpOptions = NWProtocolTCP.Options()
        tcpOptions.enableKeepalive = true
        tcpOptions.keepaliveIdle = 2

        connection = NWConnection(
            host: nwHost,
            port: nwPort,
            using: .tcp
        )

        connection?.stateUpdateHandler = { [weak self] newState in
            guard let self = self else { return }

            switch newState {
            case .ready:
                self.connectionState = "connected"

                // 启动消息接收
                self.startMessageReceiver()

                // 启动心跳
                self.startHeartbeat()

                // 通知连接成功
                self.notifyConnected(TCPResultType(UTSJSONObject([
                    "code": 0,
                    "data": "Connected successfully"
                ])))

            case .failed(let error):
                self.connectionState = "disconnected"
                self.notifyError(TCPResultType(UTSJSONObject([
                    "code": 3,
                    "error": error.localizedDescription
                ])))

            case .cancelled:
                self.connectionState = "disconnected"
                self.notifyDisconnected(TCPResultType(UTSJSONObject([
                    "code": 0,
                    "data": "Connection cancelled"
                ])))

            case .waiting(let error):
                self.connectionState = "disconnected"
                self.notifyError(TCPResultType(UTSJSONObject([
                    "code": 4,
                    "error": error.localizedDescription
                ])))

            case .setup:
                 self.connectionState = "connecting"

            @unknown default:
                break
            }
        }

        connection?.start(queue: queue)
    }

    /**
     * 断开连接
     */
    func disconnect() {
        guard connectionState != "disconnected" && connectionState != "disconnecting" else {
            return
        }

        connectionState = "disconnecting"

        // 停止心跳
        stopHeartbeat()

        // 安全地关闭连接
        if let conn = connection {
            conn.cancel()
            connection = nil
        }

        connectionState = "disconnected"
        notifyDisconnected(TCPResultType(UTSJSONObject([
            "code": 0,
            "data": "Disconnected successfully"
        ])))
    }

    /**
     * 发送消息
     */
    func sendMessage(_ message: String) {
        guard connectionState == "connected" else {
            notifyError(TCPResultType(UTSJSONObject([
                "code": 5,
                "error": "Client is not connected"
            ])))
            return
        }

//         guard let data = message.data(using: .utf8) else {
//             notifyError(TCPResultType(UTSJSONObject([
//                 "code": 6,
//                 "error": "Failed to encode message"
//             ])))
//             return
//         }

        let messageWithNewline = message.hasSuffix("\n") ? message : message + "\n"
                guard let data = messageWithNewline.data(using: .utf8) else {
                    notifyError(TCPResultType(UTSJSONObject([
                        "code": 6,
                        "error": "Failed to encode message"
                    ])))
                    return
                }

        connection?.send(
            content: data,
            completion: .contentProcessed({ [weak self] error in
                if let error = error {
                    self?.notifyError(TCPResultType(UTSJSONObject([
                        "code": 7,
                        "error": error.localizedDescription
                    ])))
                }
            })
        )
    }

    /**
     * 获取连接状态
     */
    func getConnectionState() -> String {
        return connectionState
    }

    /**
     * 销毁客户端实例
     */
    func destroy() {
        disconnect()
    }

    /**
     * 注册连接成功回调
     */
    func onConnected(callback: @escaping ConnectedCallbackType) {
        connectedCallback = callback
    }

    /**
     * 注册断开连接回调
     */
    func onDisconnected(callback: @escaping DisconnectedCallbackType) {
        disconnectedCallback = callback
    }

    /**
     * 注册消息接收回调
     */
    func onMessage(callback: @escaping MessageCallbackType) {
        messageCallback = callback
    }

    /**
     * 注册错误回调
     */
    func onError(callback: @escaping ErrorCallbackType) {
        errorCallback = callback
    }

    /**
     * 启用心跳
     */
    func enableHeartbeat(interval: Int = 30000, message: String = "HEARTBEAT") {
        heartbeatEnabled = true
        heartbeatInterval = TimeInterval(interval) / 1000.0
        heartbeatMessage = message

        // 如果已连接，立即启动心跳
        if connectionState == "connected" {
            startHeartbeat()
        }
    }

    /**
     * 禁用心跳
     */
    func disableHeartbeat() {
        heartbeatEnabled = false
        stopHeartbeat()
    }

    /**
     * 启动消息接收
     */
     private var messageBuffer: Data = Data()
    private func startMessageReceiver() {
            // 确保只在连接状态下接收消息
            guard connectionState == "connected" else { return }

            connection?.receive(minimumIncompleteLength: 1, maximumLength: 65536) { [weak self] (data, context, isComplete, error) in
                guard let self = self else { return }

                if let data = data, !data.isEmpty {
                    // 🔥 将新数据添加到缓冲区
                    self.messageBuffer.append(data)

                    // 🔥 尝试从缓冲区中提取完整的消息（以换行符分隔）
                    while let newlineRange = self.messageBuffer.range(of: Data([0x0A])) { // 0x0A 是 \n
                        let messageData = self.messageBuffer.subdata(in: self.messageBuffer.startIndex..<newlineRange.lowerBound)

                        // 移除已处理的数据（包括换行符）
                        self.messageBuffer.removeSubrange(self.messageBuffer.startIndex..<newlineRange.upperBound)

                        // 转换为字符串
                        if let message = String(data: messageData, encoding: .utf8) {
                            let trimmedMessage = message.trimmingCharacters(in: .whitespacesAndNewlines)
                            if !trimmedMessage.isEmpty {
                                self.notifyMessage(trimmedMessage)
                            }
                        }
                    }
                }

                if isComplete {
                    // 服务器关闭了连接
                    if self.connectionState == "connected" {
                        self.connectionState = "disconnected"
                        self.stopHeartbeat()
                        self.notifyDisconnected(TCPResultType(UTSJSONObject([
                            "code": 0,
                            "data": "Server closed the connection"
                        ])))
                    }
                    return
                }

                if let error = error {
                    if self.connectionState == "connected" {
                        self.connectionState = "disconnected"
                        self.stopHeartbeat()
                        self.notifyError(TCPResultType(UTSJSONObject([
                            "code": 9,
                            "error": error.localizedDescription
                        ])))
                    }
                    return
                }

                // 继续接收下一条消息，但要再次检查连接状态
                if self.connectionState == "connected" {
                    self.startMessageReceiver()
                }
            }
        }

    /**
     * 启动心跳
     */
    private func startHeartbeat() {
        guard heartbeatEnabled && connectionState == "connected" else {
            return
        }

        // 停止之前的心跳
        stopHeartbeat()

        // 在主线程创建定时器
        DispatchQueue.main.async { [weak self] in
            guard let self = self else { return }

            self.heartbeatTimer = Timer.scheduledTimer(withTimeInterval: self.heartbeatInterval, repeats: true) { [weak self] _ in
                guard let self = self else { return }

                // 检查心跳是否仍然启用且连接正常
                if self.heartbeatEnabled && self.connectionState == "connected" {
                    self.sendHeartbeat()
                } else {
                    self.stopHeartbeat()
                }
            }
        }
    }

    /**
     * 发送心跳消息
     */
    private func sendHeartbeat() {
        guard heartbeatEnabled && connectionState == "connected" else { return }

        guard let data = (heartbeatMessage + "\n").data(using: .utf8) else { return }  // 添加换行符确保消息完整

        connection?.send(
            content: data,
            completion: .contentProcessed({ error in
                // 心跳发送失败不需要特殊处理，让正常的错误处理机制处理
            })
        )
    }

    /**
     * 停止心跳
     */
    private func stopHeartbeat() {
        heartbeatTimer?.invalidate()
        heartbeatTimer = nil
    }



    /**
     * 通知连接成功
     */
    private func notifyConnected(_ result: TCPResultType) {
        threadManager.executeOnMainThread {
            self.connectedCallback?(self.clientId, result)
        }
    }

    /**
     * 通知断开连接
     */
    private func notifyDisconnected(_ result: TCPResultType) {
        threadManager.executeOnMainThread {
            self.disconnectedCallback?(self.clientId, result)
        }
    }

    /**
     * 通知接收到消息
     */
    private func notifyMessage(_ message: String) {
        threadManager.executeOnMainThread {
            self.messageCallback?(self.clientId, message)
        }
    }

    /**
     * 通知错误
     */
    private func notifyError(_ result: TCPResultType) {
        threadManager.executeOnMainThread {
            self.errorCallback?(self.clientId, result)
        }
    }
}
