/// TCP客户端管理器
/// 负责统一管理所有TCP客户端实例和线程资源
/// 使用单例模式
class TCPClientManager {

    // 使用单例模式
    static let shared = TCPClientManager()

    // 私有初始化方法
    private init() {}

    // 存储所有活跃的客户端实例
    private var activeClients: [String: TCPClient] = [:]

    // 线程安全锁
    private let lock = NSLock()

    // 全局队列，用于所有TCP客户端的异步操作
    private let globalQueue = DispatchQueue(
        label: "com.ohyes.tcp.global", qos: .userInitiated, attributes: .concurrent)

    // 主线程队列，用于回调
    private let mainQueue = DispatchQueue.main

    /**
     * 创建TCP客户端实例
     * @return 客户端ID
     */
    func createTCPClient() -> String {
        lock.lock()
        defer { lock.unlock() }

        let clientId = "client_\(Date().timeIntervalSince1970)_\(Int.random(in: 100000...999999))"
        let client = TCPClient(clientId: clientId)
        activeClients[clientId] = client
        return clientId
    }

    /**
     * 通过客户端ID获取TCP客户端实例
     * @param clientId 客户端ID
     * @return TCP客户端实例，如果不存在则返回nil
     */
    func getTCPClient(clientId: String) -> TCPClient? {
        lock.lock()
        defer { lock.unlock() }

        return activeClients[clientId]
    }

    /**
     * 通过客户端ID连接到服务器
     * @param clientId 客户端ID
     * @param options 连接选项
     */
    func connectClient(clientId: String, options: ConnectionOptionsType) {
        lock.lock()
        defer { lock.unlock() }

        if let client = activeClients[clientId] {
            client.connect(options: options)
        }
    }

    /**
     * 通过客户端ID断开连接
     * @param clientId 客户端ID
     */
    func disconnectClient(clientId: String) {
        lock.lock()
        defer { lock.unlock() }

        let client = activeClients[clientId]
        client?.disconnect()
    }

    /**
     * 通过客户端ID销毁客户端
     * @param clientId 客户端ID
     */
    func destroyClient(clientId: String) {
        lock.lock()
        defer { lock.unlock() }

        if let client = activeClients[clientId] {
            client.destroy()
            activeClients.removeValue(forKey: clientId)
        }
    }

    /**
     * 通过客户端ID发送消息
     * @param clientId 客户端ID
     * @param message 消息内容
     */
    func sendMessage(clientId: String, message: String) {
        lock.lock()
        defer { lock.unlock() }

        if let client = activeClients[clientId], !message.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            client.sendMessage(message)
        }
    }

    /**
     * 通过客户端ID注册连接成功回调
     * @param clientId 客户端ID
     * @param callback 连接成功回调函数
     */
    func onConnected(clientId: String, callback: @escaping ConnectedCallbackType) {
        lock.lock()
        defer { lock.unlock() }

        let client = activeClients[clientId]
        client?.onConnected(callback: callback)
    }

    /**
     * 通过客户端ID注册断开连接回调
     * @param clientId 客户端ID
     * @param callback 断开连接回调函数
     */
    func onDisconnected(clientId: String, callback: @escaping DisconnectedCallbackType) {
        lock.lock()
        defer { lock.unlock() }

        let client = activeClients[clientId]
        client?.onDisconnected(callback: callback)
    }

    /**
     * 通过客户端ID注册消息接收回调
     * @param clientId 客户端ID
     * @param callback 消息接收回调函数
     */
    func onMessage(clientId: String, callback: @escaping MessageCallbackType) {
        lock.lock()
        defer { lock.unlock() }

        let client = activeClients[clientId]
        client?.onMessage(callback: callback)
    }

    /**
     * 通过客户端ID注册错误回调
     * @param clientId 客户端ID
     * @param callback 错误回调函数
     */
    func onError(clientId: String, callback: @escaping ErrorCallbackType) {
        lock.lock()
        defer { lock.unlock() }

        let client = activeClients[clientId]
        client?.onError(callback: callback)
    }

    /**
     * 获取所有活跃的客户端ID
     * @return 客户端ID列表
     */
    func getActiveClients() -> [String] {
        lock.lock()
        defer { lock.unlock() }

        return Array(activeClients.keys)
    }

    /**
     * 获取客户端连接状态
     * @param clientId 客户端ID
     * @return 连接状态，如果客户端不存在返回"not_found"
     */
    func getClientState(clientId: String) -> String {
        lock.lock()
        defer { lock.unlock() }

        if let client = activeClients[clientId] {
            return client.getConnectionState()
        }
        return "not_found"
    }

    /**
     * 检查客户端是否存在
     * @param clientId 客户端ID
     * @return 是否存在
     */
    func clientExists(clientId: String) -> Bool {
        lock.lock()
        defer { lock.unlock() }

        return activeClients[clientId] != nil
    }

    /**
     * 启用客户端心跳
     * @param clientId 客户端ID
     * @param interval 心跳间隔，单位毫秒
     * @param message 心跳消息内容
     */
    func enableHeartbeat(clientId: String, interval: Int = 30000, message: String = "HEARTBEAT") {
        lock.lock()
        defer { lock.unlock() }

        if let client = activeClients[clientId] {
            client.enableHeartbeat(interval: interval, message: message)
        }
    }

    /**
     * 禁用客户端心跳
     * @param clientId 客户端ID
     */
    func disableHeartbeat(clientId: String) {
        lock.lock()
        defer { lock.unlock() }

        if let client = activeClients[clientId] {
            client.disableHeartbeat()
        }
    }

    /**
     * 销毁所有客户端实例
     */
    func destroyAllClients() {
        lock.lock()
        defer { lock.unlock() }

        for (_, client) in activeClients {
            client.destroy()
        }
        activeClients.removeAll()
    }

    /**
     * 在全局队列中执行任务
     * @param task 要执行的任务
     */
    func executeOnGlobalQueue(_ task: @escaping () -> Void) {
        globalQueue.async(execute: task)
    }

    /**
     * 在全局队列中执行延迟任务
     * @param task 要执行的任务
     * @param delay 延迟时间（秒）
     */
    func executeOnGlobalQueueAfterDelay(_ task: @escaping () -> Void, delay: TimeInterval) {
        globalQueue.asyncAfter(deadline: .now() + delay, execute: task)
    }

    /**
     * 在主线程中执行任务
     * @param task 要执行的任务
     */
    func executeOnMainThread(_ task: @escaping () -> Void) {
        mainQueue.async(execute: task)
    }

    /**
     * 销毁管理器，释放所有资源
     */
    func destroy() {
        lock.lock()
        defer { lock.unlock() }

        for (_, client) in activeClients {
            client.destroy()
        }
        activeClients.removeAll()
    }
}

