import Foundation

class TCPServerManager {

    static let shared = TCPServerManager()

    private var server: TCPServer?

    // 保存回调引用
    private var savedOnStarted: (() -> Void)?
    private var savedOnClientConnected: ((String) -> Void)?
    private var savedOnClientDisconnected: ((String) -> Void)?
    private var savedOnMessageReceived: ((String, String) -> Void)?
    private var savedOnError: ((String) -> Void)?

    private init() {}

    func startServer(port: Int) {
        // 如果已存在，先停止
        if server != nil {
            server?.stop()
        }

        // 创建新实例
        server = TCPServer()

        // 重新绑定回调
        server?.onStarted = savedOnStarted
        server?.onClientConnected = savedOnClientConnected
        server?.onClientDisconnected = savedOnClientDisconnected
        server?.onMessageReceived = savedOnMessageReceived
        server?.onError = savedOnError

        server?.start(port: port)
    }

    func stopServer() {
        server?.stop()
        server = nil
    }

    func sendToClient(clientId: String, msg: String) {
        server?.sendToClient(clientId: clientId, msg: msg)
    }

    func broadcast(msg: String) {
        server?.broadcast(msg: msg)
    }

    func getClients() -> [String] {
        return server?.getClientList() ?? []
    }

    func onStarted(callback: @escaping () -> Void) {
        savedOnStarted = callback
        server?.onStarted = callback
    }

    func onClientConnected(callback: @escaping (String) -> Void) {
        savedOnClientConnected = callback
        server?.onClientConnected = callback
    }

    func onClientDisconnected(callback: @escaping (String) -> Void) {
        savedOnClientDisconnected = callback
        server?.onClientDisconnected = callback
    }

    func onMessageReceived(callback: @escaping (String, String) -> Void) {
        savedOnMessageReceived = callback
        server?.onMessageReceived = callback
    }

