package uts.sdk.modules.redTcp

import tcp from '@ohos.net.tcp';
import util from '@ohos.util';

// 回调类型定义
type ConnectedCallbackType = (clientId: string, result: TCPResultType) => void;
type DisconnectedCallbackType = (clientId: string, result: TCPResultType) => void;
type MessageCallbackType = (clientId: string, message: string) => void;
type ErrorCallbackType = (clientId: string, result: TCPResultType) => void;

// TCP 结果
export class TCPResultType {
    code: number = 0;
    data?: string;
    error?: string;

    constructor(obj?: Partial<TCPResultType>) {
        if (obj) {
            this.code = obj.code ?? 0;
            this.data = obj.data;
            this.error = obj.error;
        }
    }
}

// 连接配置
export interface ConnectionOptionsType {
    serverHost: string;
    serverPort: number;
    timeout?: number;
    enableHeartbeat?: boolean;
    heartbeatInterval?: number;
    heartbeatMessage?: string;
}

export class TCPClient {
    private clientId: string;
    private connectionState: string = "disconnected";

    // Socket
    private socket: tcp.TCPSocket | null = null;
    private options: ConnectionOptionsType | null = null;

    // 回调
    private connectedCallback: ConnectedCallbackType | null = null;
    private disconnectedCallback: DisconnectedCallbackType | null = null;
    private messageCallback: MessageCallbackType | null = null;
    private errorCallback: ErrorCallbackType | null = null;

    // 心跳
    private heartbeatEnabled: boolean = false;
    private heartbeatInterval: number = 30000;
    private heartbeatMessage: string = "HEARTBEAT";
    private heartbeatTimer: number | null = null;

    constructor(clientId: string) {
        this.clientId = clientId;
    }

    // 连接服务器
    connect(options: ConnectionOptionsType): void {
        if (this.connectionState !== "disconnected") {
            this.notifyError(new TCPResultType({ code: 1, error: "Client is not disconnected" }));
            return;
        }

        this.options = options;
        this.connectionState = "connecting";

        if (options.enableHeartbeat) {
            this.heartbeatEnabled = true;
            this.heartbeatInterval = options.heartbeatInterval ?? 30000;
            this.heartbeatMessage = options.heartbeatMessage ?? "HEARTBEAT";
        }

        this.socket = tcp.createTCPSocket();

        // 连接成功
        this.socket.on("connect", () => {
            this.connectionState = "connected";
            this.startMessageReceiver();
            this.startHeartbeat();
            this.notifyConnected(new TCPResultType({ code: 0, data: "Connected successfully" }));
        });

        // 连接关闭
        this.socket.on("close", () => {
            if (this.connectionState === "connected") {
                this.connectionState = "disconnected";
                this.stopHeartbeat();
                this.notifyDisconnected(new TCPResultType({ code: 0, data: "Server closed the connection" }));
            }
        });

        // 错误
        this.socket.on("error", (err) => {
            this.connectionState = "disconnected";
            this.notifyError(new TCPResultType({ code: 3, error: err.message || "Connection error" }));
        });

        // 执行连接
        this.socket.connect({
            address: options.serverHost,
            port: options.serverPort,
            timeout: options.timeout ?? 5000
        });
    }

    // 断开连接
    disconnect(): void {
        if (this.connectionState === "disconnected" || this.connectionState === "disconnecting") return;

        this.connectionState = "disconnecting";
        this.stopHeartbeat();

        try {
            if (this.socket) {
                this.socket.off("connect");
                this.socket.off("close");
                this.socket.off("error");
                this.socket.off("message");
                this.socket.close();
            }
        } catch (e) {}

        this.socket = null;
        this.connectionState = "disconnected";
        this.notifyDisconnected(new TCPResultType({ code: 0, data: "Disconnected successfully" }));
    }

    // 发送消息
    sendMessage(message: string): void {
        if (this.connectionState !== "connected" || !this.socket) {
            this.notifyError(new TCPResultType({ code: 5, error: "Client not connected" }));
            return;
        }

        try {
            const data = util.encodeUtf8(message + "\n");
            this.socket.send(data.buffer);
        } catch (e) {
            this.notifyError(new TCPResultType({ code: 6, error: "Send failed" }));
        }
    }

    // 接收消息
    private startMessageReceiver(): void {
        if (!this.socket) return;

        this.socket.on("message", (data) => {
            try {
                const msg = util.decodeUtf8(new Uint8Array(data));
                if (msg.trim().length > 0) {
                    this.notifyMessage(msg);
                }
            } catch (e) {}
        });
    }

    // 心跳
    private startHeartbeat(): void {
        if (!this.heartbeatEnabled || this.connectionState !== "connected") return;
        this.stopHeartbeat();

        this.heartbeatTimer = setInterval(() => {
            if (this.connectionState === "connected") {
                this.sendMessage(this.heartbeatMessage);
            }
        }, this.heartbeatInterval);
    }

    private stopHeartbeat(): void {
        if (this.heartbeatTimer) {
            clearInterval(this.heartbeatTimer);
            this.heartbeatTimer = null;
        }
    }

    enableHeartbeat(interval: number = 30000, message: string = "HEARTBEAT"): void {
        this.heartbeatEnabled = true;
        this.heartbeatInterval = interval;
        this.heartbeatMessage = message;
        if (this.connectionState === "connected") this.startHeartbeat();
    }

    disableHeartbeat(): void {
        this.heartbeatEnabled = false;
        this.stopHeartbeat();
    }

    // 回调注册
    onConnected(callback: ConnectedCallbackType): void { this.connectedCallback = callback; }
    onDisconnected(callback: DisconnectedCallbackType): void { this.disconnectedCallback = callback; }
    onMessage(callback: MessageCallbackType): void { this.messageCallback = callback; }
    onError(callback: ErrorCallbackType): void { this.errorCallback = callback; }

    // 通知
    private notifyConnected(result: TCPResultType): void { this.connectedCallback?.(this.clientId, result); }
    private notifyDisconnected(result: TCPResultType): void { this.disconnectedCallback?.(this.clientId, result); }
    private notifyMessage(message: string): void { this.messageCallback?.(this.clientId, message); }
    private notifyError(result: TCPResultType): void { this.errorCallback?.(this.clientId, result); }

    getConnectionState(): string { return this.connectionState; }
    destroy(): void {
        this.disconnect();
        this.connectedCallback = null;
        this.disconnectedCallback = null;
        this.messageCallback = null;
        this.errorCallback = null;
    }
}
