import { TCPClient, TCPResultType, ConnectionOptionsType } from './TCPClient';

// 回调类型定义
type ConnectedCallbackType = (clientId: string, result: TCPResultType) => void;
type DisconnectedCallbackType = (clientId: string, result: TCPResultType) => void;
type MessageCallbackType = (clientId: string, message: string) => void;
type ErrorCallbackType = (clientId: string, result: TCPResultType) => void;

// 全局单例管理
export class TCPClientManager {
    private static instance: TCPClientManager;
    private activeClients: Map<string, TCPClient> = new Map();

    // 🔥 保存回调引用
    private connectedCallbacks: Map<string, ConnectedCallbackType> = new Map();
    private disconnectedCallbacks: Map<string, DisconnectedCallbackType> = new Map();
    private messageCallbacks: Map<string, MessageCallbackType> = new Map();
    private errorCallbacks: Map<string, ErrorCallbackType> = new Map();

    private constructor() {}

    // 单例
    public static getInstance(): TCPClientManager {
        if (!this.instance) {
            this.instance = new TCPClientManager();
        }
        return this.instance;
    }

    // 🔥 创建客户端
    createTCPClient(): string {
        const clientId = `client_${Date.now()}_${Math.floor(Math.random() * 900000) + 100000}`;
        const client = new TCPClient(clientId);
        this.activeClients.set(clientId, client);
        return clientId;
    }

    // 获取或创建客户端
    getOrCreateClient(clientId: string): TCPClient {
        let client = this.activeClients.get(clientId);
        if (!client) {
            client = new TCPClient(clientId);
            this.activeClients.set(clientId, client);
        }
        return client;
    }

    // 🔥 连接客户端
    connectClient(clientId: string, options: ConnectionOptionsType): void {
        const client = this.activeClients.get(clientId);
        if (client) {
            // 先注册回调
            if (this.connectedCallbacks.has(clientId)) {
                client.onConnected(this.connectedCallbacks.get(clientId)!);
            }
            if (this.disconnectedCallbacks.has(clientId)) {
                client.onDisconnected(this.disconnectedCallbacks.get(clientId)!);
            }
            if (this.messageCallbacks.has(clientId)) {
                client.onMessage(this.messageCallbacks.get(clientId)!);
            }
            if (this.errorCallbacks.has(clientId)) {
                client.onError(this.errorCallbacks.get(clientId)!);
            }

            client.connect(options);
        }
    }

    // 🔥 断开连接
    disconnectClient(clientId: string): void {
        const client = this.activeClients.get(clientId);
        if (client) {
            client.disconnect();
        }
    }

    // 🔥 发送消息
    sendMessage(clientId: string, message: string): void {
        const client = this.activeClients.get(clientId);
        if (client) {
            client.sendMessage(message);
        }
    }

    // 🔥 注册回调
    onConnected(clientId: string, callback: ConnectedCallbackType): void {
        this.connectedCallbacks.set(clientId, callback);
        const client = this.activeClients.get(clientId);
        if (client) {
            client.onConnected(callback);
        }
    }

    onDisconnected(clientId: string, callback: DisconnectedCallbackType): void {
        this.disconnectedCallbacks.set(clientId, callback);
        const client = this.activeClients.get(clientId);
        if (client) {
            client.onDisconnected(callback);
        }
    }

    onMessage(clientId: string, callback: MessageCallbackType): void {
        this.messageCallbacks.set(clientId, callback);
        const client = this.activeClients.get(clientId);
        if (client) {
            client.onMessage(callback);
        }
    }

    onError(clientId: string, callback: ErrorCallbackType): void {
        this.errorCallbacks.set(clientId, callback);
        const client = this.activeClients.get(clientId);
        if (client) {
            client.onError(callback);
        }
    }

    // 🔥 获取活跃客户端列表
    getActiveClients(): string[] {
        return Array.from(this.activeClients.keys());
    }

    // 🔥 检查客户端是否存在
    clientExists(clientId: string): boolean {
        return this.activeClients.has(clientId);
    }

    // 🔥 启用心跳
    enableHeartbeat(clientId: string, interval: number = 30000, message: string = "HEARTBEAT"): void {
        const client = this.activeClients.get(clientId);
        if (client) {
            client.enableHeartbeat(interval, message);
        }
    }

    // 🔥 禁用心跳
    disableHeartbeat(clientId: string): void {
        const client = this.activeClients.get(clientId);
        if (client) {
            client.disableHeartbeat();
        }
    }

    // 获取状态
    getClientState(clientId: string): string {
        return this.activeClients.get(clientId)?.getConnectionState() ?? "disconnected";
    }

    // 销毁指定客户端
    destroyClient(clientId: string): void {
        const client = this.activeClients.get(clientId);
        if (client) {
            client.destroy();
            this.activeClients.delete(clientId);
            // 清理回调
            this.connectedCallbacks.delete(clientId);
            this.disconnectedCallbacks.delete(clientId);
            this.messageCallbacks.delete(clientId);
            this.errorCallbacks.delete(clientId);
        }
    }

    // 销毁所有
    destroyAllClients(): void {
        this.activeClients.forEach(client => client.destroy());
        this.activeClients.clear();
        this.connectedCallbacks.clear();
        this.disconnectedCallbacks.clear();
        this.messageCallbacks.clear();
        this.errorCallbacks.clear();
    }
}

