package uts.sdk.modules.redTcp

import socket from '@ohos.net.socket';
import util from '@ohos.util';

// 回调类型定义
type ServerStartedCallback = () => void;
type ClientConnectedCallback = (clientId: string) => void;
type ClientDisconnectedCallback = (clientId: string) => void;
type ServerMessageCallback = (clientId: string, message: string) => void;
type ServerErrorCallback = (message: string) => void;

export class TCPServer {
    // 回调函数
    public onStarted: ServerStartedCallback | null = null;
    public onClientConnected: ClientConnectedCallback | null = null;
    public onClientDisconnected: ClientDisconnectedCallback | null = null;
    public onMessageReceived: ServerMessageCallback | null = null;
    public onError: ServerErrorCallback | null = null;

    // 🔥 服务相关 - 使用正确的 API
    private serverSocket: socket.TCPSocketServer | null = null;
    private isRunning: boolean = false;
    private clients: Map<string, socket.TCPSocketConnection> = new Map();

    // 启动服务
    start(port: number): void {
        if (this.isRunning) return;

        try {
            // 🔥 创建 TCP 服务器实例
            this.serverSocket = socket.constructTCPSocketServerInstance();
            this.isRunning = true;

            // 🔥 监听连接事件
            this.serverSocket.on('connect', (client: socket.TCPSocketConnection) => {
                const remoteInfo = client.remoteInfo;
                const clientId = `${remoteInfo.address}:${remoteInfo.port}`;

                this.clients.set(clientId, client);

                // 🔥 为每个客户端设置消息监听
                client.on('message', (value: socket.SocketMessageInfo) => {
                    try {
                        const msg = util.decodeUtf8(new Uint8Array(value.message));

                        // 按换行符分割消息
                        let buffer = msg;
                        let newlineIndex: number;
                        while ((newlineIndex = buffer.indexOf('\n')) !== -1) {
                            const line = buffer.substring(0, newlineIndex);
                            buffer = buffer.substring(newlineIndex + 1);

                            const trimmedMsg = line.trim();
                            if (trimmedMsg.length > 0) {
                                this.messageReceived(clientId, trimmedMsg);
                            }
                        }
                    } catch (e) {
                        console.error(`Message decode error: ${e}`);
                    }
                });

                // 🔥 监听客户端关闭
                client.on('close', () => {
                    this.clientDisconnected(clientId);
                });

                // 🔥 监听客户端错误
                client.on('error', (err: Error) => {
                    console.error(`Client ${clientId} error: ${err.message}`);
                    this.clientDisconnected(clientId);
                });

                // 通知新客户端连接
                if (this.onClientConnected) {
                    this.onClientConnected(clientId);
                }
            });

            // 🔥 监听服务器错误
            this.serverSocket.on('error', (err: Error) => {
                this.isRunning = false;
                if (this.onError) {
                    this.onError(`Server error: ${err.message}`);
                }
            });

            // 🔥 绑定并监听端口
            const listenAddr: socket.NetAddress = {
                address: '0.0.0.0',
                port: port,
                family: 1  // IPv4
            };

            this.serverSocket.listen(listenAddr, (err: Error) => {
                if (err) {
                    this.isRunning = false;
                    if (this.onError) {
                        this.onError(`Failed to listen: ${err.message}`);
                    }
                } else {
                    // 🔥 监听成功，触发回调
                    if (this.onStarted) {
                        this.onStarted();
                    }
                }
            });

        } catch (e: any) {
            this.isRunning = false;
            if (this.onError) {
                this.onError(`Failed to start server: ${e.message}`);
            }
        }
    }

    // 停止服务
    stop(): void {
        this.isRunning = false;

        // 关闭所有客户端
        this.clients.forEach((client, clientId) => {
            try {
                client.off('message');
                client.off('close');
                client.off('error');
                client.close();
            } catch (e) {}
        });
        this.clients.clear();

        // 关闭服务器
        try {
            if (this.serverSocket) {
                this.serverSocket.off('connect');
                this.serverSocket.off('error');
                this.serverSocket.close();
                this.serverSocket = null;
            }
        } catch (e) {}
    }

    // 发送消息给指定客户端
    sendToClient(clientId: string, msg: string): void {
        const client = this.clients.get(clientId);
        if (client) {
            try {
                const messageWithNewline = msg.endsWith('\n') ? msg : msg + '\n';
                const data = util.encodeUtf8(messageWithNewline);
                client.send({ data: data.buffer });
            } catch (e) {
                console.error(`Send to ${clientId} failed: ${e}`);
            }
        }
    }

    // 广播消息
    broadcast(msg: string): void {
        this.clients.forEach((client, clientId) => {
            try {
                const messageWithNewline = msg.endsWith('\n') ? msg : msg + '\n';
                const data = util.encodeUtf8(messageWithNewline);
                client.send({ data: data.buffer });
            } catch (e) {
                console.error(`Broadcast to ${clientId} failed: ${e}`);
            }
        });
    }

    // 获取客户端列表
    getClientList(): string[] {
        return Array.from(this.clients.keys());
    }

    // 客户端断开处理
    clientDisconnected(clientId: string): void {
        const client = this.clients.get(clientId);
        if (client) {
            try {
                client.off('message');
                client.off('close');
                client.off('error');
                client.close();
            } catch (e) {}
        }

        this.clients.delete(clientId);

        if (this.onClientDisconnected) {
            this.onClientDisconnected(clientId);
        }
    }

    // 收到消息处理
    messageReceived(clientId: string, message: string): void {
        if (this.onMessageReceived) {
            this.onMessageReceived(clientId, message);
        }
    }
}

